"use client";

import React, { useEffect, useState } from "react";
import {
  ShieldAlert,
  RefreshCw,
  Trash2,
  Shield,
  User,
  Settings,
  AlertOctagon,
  Activity,
  AlertTriangle,
  ScrollText,
  UserCheck,
} from "lucide-react";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";

interface UserProfile {
  id: string;
  username: string;
  email: string;
  role: string;
  discordId: string | null;
  githubId: string | null;
  isVerified: boolean;
  createdAt: string;
}

interface StaffProfile {
  id: string;
  userId: string;
  role: string;
  active: boolean;
  scopes: unknown[];
  user: {
    id: string;
    username: string;
    email: string;
    role: string;
  };
}

export default function AdminPanel() {
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [reports, setReports] = useState<any[]>([]);
  const [sellerVerifications, setSellerVerifications] = useState<any[]>([]);
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [staff, setStaff] = useState<StaffProfile[]>([]);
  const [health, setHealth] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  async function fetchUsers() {
    try {
      setLoading(true);
      const res = await fetch("/api/admin/users");
      const data = await res.json();
      if (data.users) {
        setUsers(data.users);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  async function fetchAdminData() {
    const [healthRes, reportsRes, sellerRes, announcementsRes, staffRes] =
      await Promise.all([
        fetch("/api/admin/health"),
        fetch("/api/admin/reports"),
        fetch("/api/admin/seller-verification"),
        fetch("/api/admin/announcements"),
        fetch("/api/admin/staff"),
      ]);
    const healthData = await healthRes.json();
    const reportsData = await reportsRes.json();
    const sellerData = await sellerRes.json();
    const announcementsData = await announcementsRes.json();
    const staffData = await staffRes.json();
    if (healthData.health) setHealth(healthData.health);
    if (reportsData.reports) setReports(reportsData.reports);
    if (sellerData.verifications)
      setSellerVerifications(sellerData.verifications);
    if (announcementsData.announcements)
      setAnnouncements(announcementsData.announcements);
    if (staffData.staff) setStaff(staffData.staff);
  }

  useEffect(() => {
    fetchUsers();
    fetchAdminData();
  }, []);

  const handleRoleChange = async (userId: string, newRole: string) => {
    try {
      const res = await fetch(`/api/admin/users/${userId}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ role: newRole }),
      });
      if (res.ok) {
        fetchUsers();
      } else {
        alert("Failed to update user role");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteUser = async (userId: string) => {
    if (
      !confirm("Are you sure you want to permanently delete/purge this user?")
    )
      return;
    try {
      const res = await fetch(`/api/admin/users/${userId}`, {
        method: "DELETE",
      });
      if (res.ok) {
        fetchUsers();
      } else {
        alert("Failed to delete user");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleToggleStaff = async (staffId: string, active: boolean) => {
    const res = await fetch(`/api/admin/staff/${staffId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ active }),
    });
    if (res.ok) fetchAdminData();
  };

  const handleDeleteStaff = async (staffId: string) => {
    const res = await fetch(`/api/admin/staff/${staffId}`, {
      method: "DELETE",
    });
    if (res.ok) fetchAdminData();
  };

  const handleReviewReport = async (
    reportId: string,
    status: "REVIEWING" | "RESOLVED" | "DISMISSED",
  ) => {
    const res = await fetch(`/api/admin/reports/${reportId}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ status }),
    });
    if (res.ok) fetchAdminData();
  };

  const handleReviewSellerVerification = async (
    verificationId: string,
    status: "REVIEWING" | "RESOLVED" | "DISMISSED",
  ) => {
    const res = await fetch(
      `/api/admin/seller-verification/${verificationId}`,
      {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
      },
    );
    if (res.ok) fetchAdminData();
  };

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
            Administrative Core
          </h1>
          <p className="text-gray-400 text-sm mt-1">
            Change system permissions, roles, and review connected developer
            nodes.
          </p>
        </div>
        <button
          onClick={fetchUsers}
          className="flex items-center gap-1.5 bg-white/5 border border-white/10 hover:bg-white/10 text-xs font-mono font-semibold px-3 py-1.5 rounded-lg text-white transition-all duration-300"
        >
          <RefreshCw className="h-3.5 w-3.5" /> Reload
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {health &&
          Object.entries(health).map(([key, value]) => (
            <Card key={key}>
              <CardHeader>
                <CardTitle className="text-xs uppercase text-gray-400">
                  {key.replace(/([A-Z])/g, " $1").trim()}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-black text-white">
                  {String(value)}
                </div>
              </CardContent>
            </Card>
          ))}
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-red-400" /> Moderation Queue
          </CardTitle>
          <CardDescription>
            Review user reports, seller verification requests, and platform
            exceptions.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-left text-sm text-gray-300">
              <thead className="bg-white/[0.02] border-b border-white/5 text-gray-400 uppercase text-xs font-mono">
                <tr>
                  <th className="px-4 py-3">Target</th>
                  <th className="px-4 py-3">Reason</th>
                  <th className="px-4 py-3">Status</th>
                  <th className="px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {reports.length === 0 ? (
                  <tr>
                    <td
                      colSpan={4}
                      className="px-4 py-8 text-center text-gray-500"
                    >
                      No moderation items.
                    </td>
                  </tr>
                ) : (
                  reports.map((report) => (
                    <tr key={report.id} className="hover:bg-white/[0.01]">
                      <td className="px-4 py-3 font-mono text-xs">
                        {report.targetType}:{report.targetId}
                      </td>
                      <td className="px-4 py-3">{report.reason}</td>
                      <td className="px-4 py-3 text-xs uppercase">
                        {report.status}
                      </td>
                      <td className="px-4 py-3 flex gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewReport(report.id, "REVIEWING")
                          }
                        >
                          Review
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewReport(report.id, "RESOLVED")
                          }
                        >
                          Resolve
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewReport(report.id, "DISMISSED")
                          }
                        >
                          Dismiss
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Shield className="h-5 w-5 text-red-400" /> Seller Verification
          </CardTitle>
          <CardDescription>
            Approve, review, or dismiss seller clearance requests.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-left text-sm text-gray-300">
              <thead className="bg-white/[0.02] border-b border-white/5 text-gray-400 uppercase text-xs font-mono">
                <tr>
                  <th className="px-4 py-3">Seller</th>
                  <th className="px-4 py-3">Status</th>
                  <th className="px-4 py-3">Details</th>
                  <th className="px-4 py-3">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {sellerVerifications.length === 0 ? (
                  <tr>
                    <td
                      colSpan={4}
                      className="px-4 py-8 text-center text-gray-500"
                    >
                      No seller verification requests.
                    </td>
                  </tr>
                ) : (
                  sellerVerifications.map((verification) => (
                    <tr key={verification.id} className="hover:bg-white/[0.01]">
                      <td className="px-4 py-3 font-mono text-xs">
                        {verification.userId}
                      </td>
                      <td className="px-4 py-3 text-xs uppercase">
                        {verification.status}
                      </td>
                      <td className="px-4 py-3 text-xs text-gray-400">
                        {JSON.stringify(verification.details || {})}
                      </td>
                      <td className="px-4 py-3 flex gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewSellerVerification(
                              verification.id,
                              "REVIEWING",
                            )
                          }
                        >
                          Review
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewSellerVerification(
                              verification.id,
                              "RESOLVED",
                            )
                          }
                        >
                          Approve
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() =>
                            handleReviewSellerVerification(
                              verification.id,
                              "DISMISSED",
                            )
                          }
                        >
                          Dismiss
                        </Button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ScrollText className="h-5 w-5 text-red-400" /> Global Announcements
          </CardTitle>
          <CardDescription>
            Review platform-wide notices and developer communications.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {announcements.length === 0 ? (
              <div className="text-sm text-gray-500">
                No announcements created yet.
              </div>
            ) : (
              announcements.map((announcement) => (
                <div
                  key={announcement.id}
                  className="rounded-lg border border-white/5 bg-white/[0.02] p-4"
                >
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <h3 className="font-semibold text-white">
                        {announcement.title}
                      </h3>
                      <p className="text-sm text-gray-400 mt-1">
                        {announcement.content}
                      </p>
                    </div>
                    <span
                      className={`text-[10px] px-2 py-1 rounded border ${announcement.active ? "text-emerald-300 border-emerald-500/20 bg-emerald-500/10" : "text-red-300 border-red-500/20 bg-red-500/10"}`}
                    >
                      {announcement.active ? "Active" : "Inactive"}
                    </span>
                  </div>
                </div>
              ))
            )}
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <UserCheck className="h-5 w-5 text-red-400" /> Staff Access
          </CardTitle>
          <CardDescription>
            Manage admin staff scopes without changing core user roles.
          </CardDescription>
        </CardHeader>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full border-collapse text-left text-sm text-gray-300">
              <thead className="bg-white/[0.02] border-b border-white/5 text-gray-400 uppercase text-xs font-mono">
                <tr>
                  <th className="px-6 py-4">Staff Member</th>
                  <th className="px-6 py-4">Staff Role</th>
                  <th className="px-6 py-4">Scopes</th>
                  <th className="px-6 py-4">Status</th>
                  <th className="px-6 py-4 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {staff.length === 0 ? (
                  <tr>
                    <td
                      colSpan={5}
                      className="px-6 py-10 text-center text-gray-500"
                    >
                      No staff profiles configured.
                    </td>
                  </tr>
                ) : (
                  staff.map((member) => (
                    <tr
                      key={member.id}
                      className="hover:bg-white/[0.01] transition-colors duration-200"
                    >
                      <td className="px-6 py-4">
                        <div className="font-semibold text-white">
                          {member.user.username}
                        </div>
                        <div className="text-xs text-gray-500 font-mono">
                          {member.user.email}
                        </div>
                      </td>
                      <td className="px-6 py-4 font-mono text-xs">
                        {member.role}
                      </td>
                      <td className="px-6 py-4 font-mono text-xs text-gray-400">
                        {Array.isArray(member.scopes)
                          ? member.scopes.join(", ")
                          : "Default"}
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className={`text-[10px] px-2 py-1 rounded border ${member.active ? "text-emerald-300 border-emerald-500/20 bg-emerald-500/10" : "text-red-300 border-red-500/20 bg-red-500/10"}`}
                        >
                          {member.active ? "Active" : "Disabled"}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button
                          onClick={() =>
                            handleToggleStaff(member.id, !member.active)
                          }
                          className="text-red-500 hover:text-red-400 transition-colors bg-red-500/10 border border-red-500/20 px-2 py-1 rounded text-xs mr-2"
                        >
                          {member.active ? "Disable" : "Enable"}
                        </button>
                        <button
                          onClick={() => handleDeleteStaff(member.id)}
                          className="text-red-500 hover:text-red-400 transition-colors bg-red-500/10 border border-red-500/20 p-2 rounded"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card className="md:col-span-2">
          <CardHeader>
            <CardTitle>Connected Platform Members</CardTitle>
            <CardDescription>
              Modify developer, seller, and administrator node clearance levels
            </CardDescription>
          </CardHeader>
          <CardContent className="p-0">
            <div className="overflow-x-auto">
              <table className="w-full border-collapse text-left text-sm text-gray-300">
                <thead className="bg-white/[0.02] border-b border-white/5 text-gray-400 uppercase text-xs font-mono">
                  <tr>
                    <th className="px-6 py-4">User</th>
                    <th className="px-6 py-4">Clearance Role</th>
                    <th className="px-6 py-4">Discord ID</th>
                    <th className="px-6 py-4">GitHub ID</th>
                    <th className="px-6 py-4">Joined Date</th>
                    <th className="px-6 py-4 text-right">Purge</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {loading ? (
                    <tr>
                      <td colSpan={6} className="text-center py-10">
                        <RefreshCw className="h-6 w-6 text-red-500 animate-spin mx-auto" />
                      </td>
                    </tr>
                  ) : users.length === 0 ? (
                    <tr>
                      <td
                        colSpan={6}
                        className="text-center py-10 text-gray-500"
                      >
                        No active users loaded.
                      </td>
                    </tr>
                  ) : (
                    users.map((u) => (
                      <tr
                        key={u.id}
                        className="hover:bg-white/[0.01] transition-colors duration-200"
                      >
                        <td className="px-6 py-4">
                          <div className="flex flex-col">
                            <span className="text-white font-semibold flex items-center gap-1.5">
                              <User className="h-3.5 w-3.5 text-red-400" />
                              {u.username}
                            </span>
                            <span className="text-xs text-gray-500 font-mono">
                              {u.email}
                            </span>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <select
                            value={u.role}
                            onChange={(e) =>
                              handleRoleChange(u.id, e.target.value)
                            }
                            className="bg-black/40 border border-white/10 text-xs font-mono font-semibold text-red-300 rounded px-2.5 py-1.5 focus:outline-none focus:ring-1 focus:ring-red-500"
                          >
                            <option value="ADMIN">ADMIN</option>
                            <option value="SELLER">SELLER</option>
                            <option value="DEVELOPER">DEVELOPER</option>
                            <option value="USER">USER</option>
                          </select>
                        </td>
                        <td className="px-6 py-4 font-mono text-xs text-gray-400">
                          {u.discordId || (
                            <span className="italic text-gray-600">
                              Not Linked
                            </span>
                          )}
                        </td>
                        <td className="px-6 py-4 font-mono text-xs text-gray-400">
                          {u.githubId || (
                            <span className="italic text-gray-600">
                              Not Linked
                            </span>
                          )}
                        </td>
                        <td className="px-6 py-4 text-xs text-gray-500 font-mono">
                          {new Date(u.createdAt).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 text-right">
                          <button
                            onClick={() => handleDeleteUser(u.id)}
                            className="text-red-500 hover:text-red-400 transition-colors bg-red-500/10 border border-red-500/20 p-2 rounded hover:bg-red-500 hover:text-white"
                          >
                            <Trash2 className="h-4 w-4" />
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>

        <div className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-1.5">
                <Settings className="h-5 w-5 text-red-400" />
                <span>Gateway Settings</span>
              </CardTitle>
              <CardDescription>Global server settings</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex items-center justify-between p-3 bg-white/[0.02] border border-white/5 rounded-lg">
                <div className="flex flex-col">
                  <span className="text-sm font-semibold text-white">
                    Maintenance Mode
                  </span>
                  <span className="text-[10px] text-gray-500">
                    Block new API key creations
                  </span>
                </div>
                <div className="h-6 w-11 rounded-full bg-gray-800 p-0.5 cursor-pointer flex items-center justify-start border border-white/5">
                  <div className="h-5 w-5 rounded-full bg-gray-400" />
                </div>
              </div>

              <div className="flex items-center justify-between p-3 bg-white/[0.02] border border-white/5 rounded-lg">
                <div className="flex flex-col">
                  <span className="text-sm font-semibold text-white">
                    Advanced BIOS Audit
                  </span>
                  <span className="text-[10px] text-gray-500">
                    Require direct kernel BIOS keys
                  </span>
                </div>
                <div className="h-6 w-11 rounded-full bg-red-500/30 p-0.5 cursor-pointer flex items-center justify-end border border-red-500/40">
                  <div className="h-5 w-5 rounded-full bg-red-400" />
                </div>
              </div>
            </CardContent>
          </Card>

          <Card className="border-red-500/15">
            <CardHeader>
              <CardTitle className="flex items-center gap-1.5 text-red-400">
                <AlertOctagon className="h-5 w-5 text-red-400" />
                <span>Zone Defenses</span>
              </CardTitle>
              <CardDescription>Suspicious activity triggers</CardDescription>
            </CardHeader>
            <CardContent className="text-xs text-gray-400 leading-relaxed space-y-2">
              <p>
                Platform monitors multi-HWID locking changes across different IP
                zones. Attempts to decrypt memory modules using custom headers
                are automatically blocked.
              </p>
              <div className="p-2 bg-red-950/20 border border-red-500/10 rounded font-mono text-[10px] text-red-300">
                AUTO-BAN ON REVERSE ENGINEER: ON
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Globe, Plus, ShieldCheck, Trash2 } from "lucide-react";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface DomainItem {
  id: string;
  domain: string;
  dnsChallenge: string;
  verifiedAt: string | null;
  primary: boolean;
}

export default function DomainsPage() {
  const [domains, setDomains] = useState<DomainItem[]>([]);
  const [domainInput, setDomainInput] = useState("");
  const [loading, setLoading] = useState(true);

  async function fetchDomains() {
    const res = await fetch("/api/domains");
    const data = await res.json();
    if (data.domains) setDomains(data.domains);
    setLoading(false);
  }

  async function addDomain() {
    const res = await fetch("/api/domains", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ domain: domainInput }),
    });
    if (res.ok) {
      setDomainInput("");
      await fetchDomains();
    } else {
      alert("Failed to add domain");
    }
  }

  async function deleteDomain(id: string) {
    const res = await fetch(`/api/domains?id=${id}`, { method: "DELETE" });
    if (res.ok) await fetchDomains();
  }

  useEffect(() => {
    fetchDomains();
  }, []);

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
          Custom Domains
        </h1>
        <p className="text-gray-400 text-sm mt-1">
          Manage verified app domains and DNS challenges.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Globe className="h-5 w-5 text-red-400" /> Add Domain
          </CardTitle>
          <CardDescription>
            Create a domain record and verify it with the generated DNS
            challenge.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-3">
            <Input
              value={domainInput}
              onChange={(event) => setDomainInput(event.target.value)}
              placeholder="app.example.com"
            />
            <Button onClick={addDomain}>
              <Plus className="h-4 w-4 mr-2" /> Add
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Verified Domain Nodes</CardTitle>
