"use client";

import React, { useEffect, useState } from "react";
import { Globe, Plus, ShieldCheck, Trash2 } from "lucide-react";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface DomainItem {
  id: string;
  domain: string;
  dnsChallenge: string;
  verifiedAt: string | null;
  primary: boolean;
}

export default function DomainsPage() {
  const [domains, setDomains] = useState<DomainItem[]>([]);
  const [domainInput, setDomainInput] = useState("");
  const [loading, setLoading] = useState(true);

  async function fetchDomains() {
    const res = await fetch("/api/domains");
    const data = await res.json();
    if (data.domains) setDomains(data.domains);
    setLoading(false);
  }

  async function addDomain() {
    const res = await fetch("/api/domains", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ domain: domainInput }),
    });
    if (res.ok) {
      setDomainInput("");
      await fetchDomains();
    } else {
      alert("Failed to add domain");
    }
  }

  async function deleteDomain(id: string) {
    const res = await fetch(`/api/domains?id=${id}`, { method: "DELETE" });
    if (res.ok) await fetchDomains();
  }

  useEffect(() => {
    fetchDomains();
  }, []);

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
          Custom Domains
        </h1>
        <p className="text-gray-400 text-sm mt-1">
          Manage verified app domains and DNS challenges.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Globe className="h-5 w-5 text-red-400" /> Add Domain
          </CardTitle>
          <CardDescription>
            Create a domain record and verify it with the generated DNS
            challenge.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-3">
            <Input
              value={domainInput}
              onChange={(event) => setDomainInput(event.target.value)}
              placeholder="app.example.com"
            />
            <Button onClick={addDomain}>
              <Plus className="h-4 w-4 mr-2" /> Add
            </Button>
          </div>
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle>Verified Domain Nodes</CardTitle>
          <CardDescription>
            Use the DNS challenge to prove ownership before accepting this host.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {loading ? (
              <p className="text-gray-500">Loading domains...</p>
            ) : domains.length === 0 ? (
              <p className="text-gray-500">No custom domains configured.</p>
            ) : (
              domains.map((domain) => (
                <div
                  key={domain.id}
                  className="flex flex-col md:flex-row items-start md:items-center justify-between gap-3 rounded-lg border border-white/5 bg-white/[0.02] p-4"
                >
                  <div>
                    <div className="font-semibold text-white">
                      {domain.domain}
                    </div>
                    <div className="text-xs text-gray-400 font-mono mt-1">
                      TXT challenge: {domain.dnsChallenge}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span
                      className={`text-[10px] px-2 py-1 rounded border ${domain.verifiedAt ? "text-emerald-300 border-emerald-500/20 bg-emerald-500/10" : "text-amber-300 border-amber-500/20 bg-amber-500/10"}`}
                    >
                      {domain.verifiedAt ? "Verified" : "Pending"}
                    </span>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => deleteDomain(domain.id)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Users, Plus, Copy, ShieldCheck } from "lucide-react";
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface TeamItem {
  id: string;
  name: string;
  ownerId: string;
  owner: { username: string };
  members: { role: string; user: { id: string; username: string } }[];
  invites: { id: string; email: string; role: string }[];
}

export default function TeamsPage() {
  const [teams, setTeams] = useState<TeamItem[]>([]);
  const [teamName, setTeamName] = useState("");
  const [inviteEmail, setInviteEmail] = useState<Record<string, string>>({});
  const [inviteToken, setInviteToken] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  async function fetchTeams() {
    const res = await fetch("/api/teams");
    const data = await res.json();
    if (data.teams) setTeams(data.teams);
    setLoading(false);
  }

  async function createTeam() {
    const res = await fetch("/api/teams", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name: teamName }),
    });
    if (res.ok) {
      setTeamName("");
      await fetchTeams();
    } else {
      alert("Failed to create team");
    }
  }

  async function createInvite(teamId: string) {
    const res = await fetch(`/api/teams/${teamId}/invites`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: inviteEmail[teamId], role: "MEMBER" }),
    });
    const data = await res.json();
    if (res.ok) {
      setInviteToken(data.token);
      await fetchTeams();
    } else {
      alert("Failed to create invite");
    }
  }

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
          Team Accounts
        </h1>
        <p className="text-gray-400 text-sm mt-1">
          Create teams, invite members, and manage shared script ownership.
        </p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Users className="h-5 w-5 text-red-400" /> Create Team
          </CardTitle>
          <CardDescription>
            Team owners and managers can invite members and share resources.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col md:flex-row gap-3">
            <Input
              value={teamName}
              onChange={(event) => setTeamName(event.target.value)}
              placeholder="Team name"
            />
            <Button onClick={createTeam}>
              <Plus className="h-4 w-4 mr-2" /> Create
            </Button>
          </div>
        </CardContent>
      </Card>

      {inviteToken && (
        <Card className="border-emerald-500/20">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Copy className="h-5 w-5 text-emerald-400" /> Invite Link
            </CardTitle>
            <CardDescription>
              Send this one-time invite link to the selected member.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="font-mono text-xs text-emerald-300 break-all">
              {typeof window !== "undefined"
                ? `${window.location.origin}/api/teams/invites/${inviteToken}/accept`
                : inviteToken}
            </div>
          </CardContent>
        </Card>
      )}

      <Card>
        <CardHeader>
          <CardTitle>Teams</CardTitle>
          <CardDescription>
            Current team nodes, members, and pending invites.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {loading ? (
              <p className="text-gray-500">Loading teams...</p>
            ) : teams.length === 0 ? (
              <p className="text-gray-500">No teams created yet.</p>
            ) : (
              teams.map((team) => (
                <div
                  key={team.id}
                  className="rounded-lg border border-white/5 bg-white/[0.02] p-4"
                >
                  <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-3">
                    <div>
                      <h3 className="font-semibold text-white">{team.name}</h3>
                      <p className="text-xs text-gray-500 mt-1">
                        Owner: {team.owner?.username || team.ownerId}
                      </p>
                    </div>
                    <div className="flex flex-col gap-2">
                      <Input
                        value={inviteEmail[team.id] || ""}
                        onChange={(event) =>
                          setInviteEmail({
                            ...inviteEmail,
                            [team.id]: event.target.value,
                          })
                        }
                        placeholder="member@example.com"
                      />
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => createInvite(team.id)}
                      >
                        Invite Member
                      </Button>
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4">
                    <div>
                      <div className="text-xs uppercase text-gray-500 mb-2">
                        Members
                      </div>
                      {team.members.map((member) => (
                        <div
                          key={member.user.id}
                          className="text-sm text-gray-300 flex items-center gap-2"
                        >
                          <ShieldCheck className="h-3.5 w-3.5 text-red-400" />{" "}
                          {member.user.username}{" "}
                          <span className="text-[10px] text-gray-500">
                            {member.role}
                          </span>
                        </div>
                      ))}
                    </div>
                    <div>
                      <div className="text-xs uppercase text-gray-500 mb-2">
                        Pending Invites
                      </div>
                      {team.invites.length === 0 ? (
                        <p className="text-sm text-gray-500">
                          No pending invites.
                        </p>
                      ) : (
                        team.invites.map((invite) => (
                          <div
                            key={invite.id}
                            className="text-sm text-gray-300"
                          >
                            {invite.email}{" "}
                            <span className="text-[10px] text-gray-500">
                              {invite.role}
                            </span>
                          </div>
                        ))
                      )}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

"use client"

import React, { useEffect, useState } from "react";
import { Link2, Plus, Trash2, RefreshCw, X, ShieldAlert, KeyRound } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";

interface Webhook {
  id: string;
  url: string;
  events: string;
  secret: string | null;
  active: boolean;
  createdAt: string;
}

export default function WebhooksPage() {
  const [webhooks, setWebhooks] = useState<Webhook[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);

  // Form states
  const [url, setUrl] = useState("");
  const [secret, setSecret] = useState("");
  const [eventRedeemed, setEventRedeemed] = useState(true);
  const [eventReset, setEventReset] = useState(true);

  async function fetchWebhooks() {
    try {
      setLoading(true);
      const res = await fetch("/api/webhooks");
      const data = await res.json();
      if (data.webhooks) {
        setWebhooks(data.webhooks);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchWebhooks();
  }, []);

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    const eventsArray: string[] = [];
    if (eventRedeemed) eventsArray.push("key.redeemed");
    if (eventReset) eventsArray.push("hwid.reset");

    try {
      const res = await fetch("/api/webhooks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          url,
          secret,
          events: eventsArray.join(","),
        }),
      });

      if (res.ok) {
        fetchWebhooks();
        setModalOpen(false);
        setUrl("");
        setSecret("");
      } else {
        const data = await res.json();
        alert(data.error || "Failed to register webhook");
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this webhook endpoint?")) return;
    try {
      const res = await fetch(`/api/webhooks/${id}`, { method: "DELETE" });
      if (res.ok) {
        fetchWebhooks();
      } else {
        alert("Failed to delete webhook");
      }
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="space-y-8">
      {/* Page Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-extrabold text-white tracking-tight glow-red">
            Webhooks Gateway
          </h1>
          <p className="text-gray-400 text-sm mt-1">
            Send real-time JSON event payloads to your servers or Discord integrations.
          </p>
        </div>
        <Button onClick={() => setModalOpen(true)} className="gap-2" variant="glow">
          <Plus className="h-4 w-4" /> Add Endpoint
        </Button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20">
          <RefreshCw className="h-10 w-10 text-red-500 animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {webhooks.length === 0 ? (
            <div className="col-span-full py-16 text-center border border-white/5 bg-black/20 rounded-xl text-gray-400">
              <Link2 className="h-12 w-12 text-gray-600 mx-auto mb-3" />
              <p className="font-semibold text-lg">No webhooks registered yet</p>
              <p className="text-xs text-gray-500 mt-1">
                Receive instant notifications on key redemptions and hwid updates.
              </p>
            </div>
          ) : (
            webhooks.map((wh) => (
              <Card key={wh.id} className="glass-panel-hover flex flex-col justify-between relative overflow-hidden">
                <CardHeader>
                  <CardTitle className="text-sm font-semibold truncate flex items-center gap-2">
                    <Link2 className="h-4 w-4 text-red-400 flex-shrink-0" />
                    <span className="truncate text-white" title={wh.url}>{wh.url}</span>
                  </CardTitle>
                  <CardDescription className="text-xs font-mono">
                    ID: {wh.id}
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="flex flex-wrap gap-1.5 pt-1">
                    {wh.events.split(",").map((event) => (
                      <span key={event} className="text-[10px] font-mono uppercase bg-red-500/10 border border-red-500/25 text-red-300 px-2 py-0.5 rounded">
                        {event}
                      </span>
                    ))}
                  </div>
                  {wh.secret && (
                    <div className="text-[10px] bg-black/40 border border-white/5 rounded-lg p-2 font-mono flex items-center justify-between">
                      <span className="text-gray-500">SECRET SIGNING KEY ACTIVE</span>
                      <span className="text-red-400 font-semibold">HMAC-SHA256</span>
                    </div>
                  )}
                </CardContent>
                <CardFooter className="border-t border-white/5 pt-4 flex justify-between items-center">
                  <span className="text-[10px] text-gray-500 font-mono">
                    Registered: {new Date(wh.createdAt).toLocaleDateString()}
                  </span>
                  <Button size="sm" variant="destructive" onClick={() => handleDelete(wh.id)} className="h-8 bg-red-950/40 border border-red-500/20 text-red-400">
                    <Trash2 className="h-3.5 w-3.5" />
                  </Button>
                </CardFooter>
              </Card>
            ))
          )}
        </div>
      )}

      {/* Add Webhook Modal */}
      {modalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-[#0b0f19] border border-white/10 rounded-xl p-6 max-w-md w-full space-y-4">
            <div className="flex items-center justify-between pb-2 border-b border-white/5">
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Link2 className="h-5 w-5 text-red-400" />
                <span>Register Webhook</span>
              </h2>
              <button onClick={() => setModalOpen(false)} className="text-gray-400 hover:text-white">
                <X className="h-5 w-5" />
              </button>
            </div>

            <form onSubmit={handleRegister} className="space-y-4 pt-2">
              <div className="space-y-1">
                <label className="text-xs text-gray-400 font-semibold uppercase">Endpoint URL</label>
                <Input
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  placeholder="https://your-api.com/webhooks"
                  required
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs text-gray-400 font-semibold uppercase">Signing Secret (Optional)</label>
                <Input
                  value={secret}
                  onChange={(e) => setSecret(e.target.value)}
                  placeholder="SuperSecureSigningSecretKey"
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs text-gray-400 font-semibold uppercase">Trigger Events</label>
                <div className="space-y-2 pt-1">
                  <label className="flex items-center gap-2 text-sm text-gray-300 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={eventRedeemed}
                      onChange={(e) => setEventRedeemed(e.target.checked)}
                      className="rounded border-white/15 bg-black/40 text-red-600 focus:ring-red-500 h-4 w-4"
                    />
                    <KeyRound className="h-4 w-4 text-red-400" />
                    <span>Key Redeemed (<code className="text-xs text-red-300 font-mono">key.redeemed</code>)</span>
                  </label>
                  <label className="flex items-center gap-2 text-sm text-gray-300 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={eventReset}
                      onChange={(e) => setEventReset(e.target.checked)}
                      className="rounded border-white/15 bg-black/40 text-red-600 focus:ring-red-500 h-4 w-4"
                    />
                    <ShieldAlert className="h-4 w-4 text-red-400" />
                    <span>HWID Reset Log (<code className="text-xs text-red-300 font-mono">hwid.reset</code>)</span>
                  </label>
                </div>
              </div>

              <div className="flex justify-end gap-2 border-t border-white/5 pt-4">
                <Button type="button" variant="outline" onClick={() => setModalOpen(false)}>
                  Cancel
                </Button>
                <Button type="submit" variant="glow">
                  Register
                </Button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

